function egoPersoenlichkeitPage() {
  return shell(`
    ${pageHeader("ego-persoenlichkeit")}
    <section class="narrow">
      <p class="eyebrow">Schaubilder · Ego-Persönlichkeit</p>
      <h1>Die Entwicklung der Ego-Persönlichkeit der 9 Enneagrammtypen</h1>
      <p class="lead-small">Die 9 Enneagrammtypen besitzen im Kern eine spezifische Ego-Persönlichkeitsstruktur, die implizit ein fundamentales Misstrauen gegenüber der Realität beinhaltet. Durch das Versagen der haltenden Umwelt fehlt bereits dem Kind das Urvertrauen — was zur Abtrennung vom Sein und zur Ego-Aktivierung führt, in deren Rahmen die Person lernt, sich „sicher" zu fühlen. Das Enneagramm zeigt die verschiedenen Varianten auf, wie sich das Ego der einzelnen Typen entwickelt, um mit den Erschütterungen, Brüchen und Unterbrechungen der haltenden Umwelt umzugehen.</p>
      <div class="psycho-img-wrap" style="margin-top:1.5rem;">
        <img src="assets/schaubilder/ego-persoenlichkeit/ego-persoenlichkeit.jpg"
             alt="Die Entwicklung der Ego-Persönlichkeit der 9 Enneagrammtypen"
             class="psycho-img" />
      </div>
      <div style="margin:2.5rem 0 0;">
        <h2 style="font-family:'EB Garamond',serif;font-size:1.4rem;color:var(--anthracite);margin:0 0 0.75rem;">Das Ego in Bewegung &ndash; und der Raum dahinter</h2>
        <img
          src="./assets/ego-in-bewegung.jpg"
          alt="Der Typ ist das Ego in Bewegung. Essenz ist der Raum, in dem es sich bewegt."
          style="width:100%;border-radius:8px;margin:0.75rem 0 1.25rem;"
        />
        <p style="font-size:0.95rem;line-height:1.75;color:var(--anthracite);margin:1rem 0;">Dieser Satz beschreibt in zwei Zeilen, was viele Seiten Theorie nur annähernd fassen: Der Enneagrammtyp ist kein festes Wesen &ndash; er ist ein Prozess. Er ist das Ego im aktiven Vollzug seiner Schutzmechanismen, Überzeugungen und Reaktionsmuster. Der Typ bewegt sich ständig: er sucht, meidet, bewertet, kontrolliert, gibt, zieht sich zurück.</p>
        <p style="font-size:0.95rem;line-height:1.75;color:var(--anthracite);margin:1rem 0;">Die Essenz hingegen ist kein weiterer Zustand, den man erst erreichen muss. Sie ist der Raum, in dem all das stattfindet &ndash; stiller, weiter, unveränderlicher. Sie ist nicht das Ziel jenseits des Egos, sondern der Hintergrund, vor dem das Ego erscheint. Wer das spürt, erlebt oft zum ersten Mal: Es gibt etwas in mir, das nicht reagiert. Das einfach da ist.</p>
        <p style="font-size:0.95rem;line-height:1.75;color:var(--anthracite);margin:1rem 0;">Das Enneagramm zeigt die Bewegungen des Egos mit großer Präzision. Aber sein eigentlicher Beitrag liegt darin, dass es durch dieses Zeigen den Blick für den Raum öffnet, in dem diese Bewegungen stattfinden. Den Typ kennen heißt: das Ego beim Namen nennen. Die Essenz spüren heißt: erkennen, dass man mehr ist als dieser Name.</p>
      </div>

      ${bookTip("der-code-deiner-persoenlichkeit", "Schritt für Schritt den eigenen Typ erkennen und Wege zur persönlichen Entwicklung finden.", "Der Code deiner Persönlichkeit")}
      ${relatedLinks([
        {route:"grundformel", label:"Grundformel"},
        {route:"kerneberzeugungen", label:"Kernüberzeugungen"},
        {route:"antriebskraefte", label:"Antriebskräfte"},
      ])}
    </section>
  `);
}

